class Admin_Model_Popup extends Admin_Model_Base_Popup {

    /**
     * @param Eshop|null $eshop
     * @return array
     */
    public static function getActivePopups(Eshop $eshop = null): array {
        if ( !$eshop )
            $eshop = Eshop::getInstance()->getEshop();

        $query = Doctrine_Query::create();
        $query->from('Admin_Model_Popup object');
        $query->where('object.Active = ?', 1);
        $query->andWhere('object.Eshop_ID = ?', $eshop->ID);
        return $query->execute()->toArray();
    }
}